import{c as a,Q as t,j as n,m as o}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"DingTalk Channel Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"channels/dingtalk.md","filePath":"channels/dingtalk.md","lastUpdated":1776332711000}'),i={name:"channels/dingtalk.md"};function r(l,e,s,p,g,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="dingtalk-channel-configuration" tabindex="-1">DingTalk Channel Configuration <a class="header-anchor" href="#dingtalk-channel-configuration" aria-label="Permalink to &quot;DingTalk Channel Configuration&quot;">​</a></h1><p>Memoh supports DingTalk bots for private chats and group chats. The adapter uses DingTalk&#39;s stream connection for inbound events and the official APIs for outbound replies and media.</p><h2 id="step-1-create-a-dingtalk-app" tabindex="-1">Step 1: Create A DingTalk App <a class="header-anchor" href="#step-1-create-a-dingtalk-app" aria-label="Permalink to &quot;Step 1: Create A DingTalk App&quot;">​</a></h2><ol><li>Open the DingTalk developer platform for your organization.</li><li>Create or choose the app that will act as your bot.</li><li>Enable the bot / messaging capability for that app.</li><li>Copy the app credentials: <ul><li><strong>App Key</strong></li><li><strong>App Secret</strong></li></ul></li></ol><p>Depending on your DingTalk environment, you may also need to grant message permissions and publish the app before it is available to end users.</p><h2 id="step-2-configure-memoh" tabindex="-1">Step 2: Configure Memoh <a class="header-anchor" href="#step-2-configure-memoh" aria-label="Permalink to &quot;Step 2: Configure Memoh&quot;">​</a></h2><ol><li>Open your bot in the Memoh Web UI.</li><li>Go to <strong>Platforms</strong>.</li><li>Click <strong>Add Channel</strong> and choose <strong>DingTalk</strong>.</li><li>Fill in <strong>App Key</strong> and <strong>App Secret</strong>.</li><li>Click <strong>Save and Enable</strong>.</li></ol><p>Memoh maintains the DingTalk stream connection automatically. For the normal setup, you do not need to manually paste a webhook callback URL.</p><h2 id="step-3-verify-messaging" tabindex="-1">Step 3: Verify Messaging <a class="header-anchor" href="#step-3-verify-messaging" aria-label="Permalink to &quot;Step 3: Verify Messaging&quot;">​</a></h2><p>After the channel is enabled:</p><ol><li>Send a private message to the DingTalk bot, or mention it in a supported group chat.</li><li>Confirm the bot receives the message and can reply.</li></ol><h2 id="features-supported" tabindex="-1">Features Supported <a class="header-anchor" href="#features-supported" aria-label="Permalink to &quot;Features Supported&quot;">​</a></h2><ul><li><strong>Private chats</strong></li><li><strong>Group chats</strong></li><li><strong>Text and Markdown-style output</strong></li><li><strong>Replies</strong></li><li><strong>Attachments and media</strong></li></ul><p>Current behavior note:</p><ul><li>Outbound responses are non-streaming on DingTalk in Memoh.</li></ul>',15)])])}const c=a(i,[["render",r]]);export{u as __pageData,c as default};
